SELECT employee_id, salary,
       AVG(salary) OVER (PARTITION BY department ORDER BY hired_at) AS dept_avg
FROM employees;

const data = [{id: 1, dept: 'A', salary: 1000}, {id: 2, dept: 'A', salary: 1200}];
data.forEach((row, idx) => {
  const deptAvg = data.filter(r => r.dept === row.dept).reduce((sum, r) => sum + r.salary, 0) / data.filter(r => r.dept === row.dept).length;
  row.dept_avg = deptAvg;
});
console.log(data);

